// Shared lock variable
volatile bool lock = FALSE;

// TestAndSet atomic instruction
bool TestAndSet(bool *target) {
    bool temp = *target;
    *target = TRUE;
    return temp;
}

// Process trying to enter critical section
void process() {
    while (TestAndSet(&lock) == TRUE);
    // Critical Section
    // ... shared resource access ...

    lock = FALSE;
    // Remainder Section
}

// Alternative: Using while loop
void process_spinlock() {
    while (TestAndSet(&lock));
    // CS begins when lock was FALSE

    // CS

    lock = FALSE;
}

#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>

#define BUFFER_SIZE 5

int buffer[BUFFER_SIZE];
int in = 0, out = 0;

// Semaphores
sem_t empty;  // Counts empty slots
sem_t full;   // Counts filled slots
sem_t mutex;  // Mutual exclusion

void* producer(void* arg) {
    int item;
    for (int i = 0; i < 10; i++) {
        item = i; // Produce item

        sem_wait(&empty);    // Wait for empty slot
        sem_wait(&mutex);    // Enter critical section

        buffer[in] = item;
        printf("Produced: %d at %d\n", item, in);
        in = (in + 1) % BUFFER_SIZE;

        sem_post(&mutex);    // Exit critical section
        sem_post(&full);     // Signal filled slot
    }
    return NULL;
}

void* consumer(void* arg) {
    int item;
    for (int i = 0; i < 10; i++) {
        sem_wait(&full);     // Wait for filled slot
        sem_wait(&mutex);    // Enter critical section

        item = buffer[out];
        printf("Consumed: %d from %d\n", item, out);
        out = (out + 1) % BUFFER_SIZE;

        sem_post(&mutex);    // Exit critical section
        sem_post(&empty);    // Signal empty slot
    }
    return NULL;
}

int main() {
    pthread_t prod, cons;

    sem_init(&empty, 0, BUFFER_SIZE);
    sem_init(&full, 0, 0);
    sem_init(&mutex, 0, 1);

    pthread_create(&prod, NULL, producer, NULL);
    pthread_create(&cons, NULL, consumer, NULL);

    pthread_join(prod, NULL);
    pthread_join(cons, NULL);

    return 0;
}
